mapper.select:

SELECT lesson_no, lesson_title, to_char(lesson_date,'YYYY/MM/DD HH24:MI') as lesson_date, lesson_category, lesson_reply_cnt, lesson_hits, user_id , user_name
FROM (
		SELECT /*+ INDEX_DESC(lesson SYS_C0025522) */
			rownum as rnum, lesson_no, lesson_title, lesson_date, lesson_category, lesson_reply_cnt, lesson_hits, user_id , user_name
		FROM lesson 
		where 



	 rownum <= #{pageNum} * #{amount}
		) lessonList
	WHERE rnum > (#{pageNum} - 1) * #{amount}

SELECT lesson_no, lesson_title, lesson_content, lesson_hits, to_char(lesson_date,'YYYY/MM/DD HH24:MI:SS') as lesson_date,  lesson_category,  user_name, user_id
FROM lesson
WHERE lesson_no = #{lesson_no}

SELECT lesson_no, lesson_title, lesson_content, lesson_category
FROM lesson
WHERE lesson_no = #{lesson_no}

mapper.update:
UPDATE lesson SET lesson_title = #{lesson_title}, lesson_content = #{lesson_content}, lesson_category = #{lesson_category}, lesson_date = sysdate
,imageFileName = #{imageFileName, jdbcType = VARCHAR}
WHERE lesson_no = #{lesson_no}
